import { OutOfStock as OutOfStockComponent } from '@/checkout/components';
import { Item as ItemModel } from '@/checkout/types/cart';
import { Container } from '@adobe-commerce/elsie/lib';
import { events } from '@adobe-commerce/event-bus';
import { HTMLAttributes } from 'preact/compat';
import { useCallback, useEffect, useState } from 'preact/hooks';

export type UpdateProductsFromCart = Array<{
  uid: string;
  quantity: number;
}>;

export interface OutOfStockProps
  extends Omit<HTMLAttributes<HTMLDivElement>, 'icon'> {
  onCartProductsUpdate?: (items: UpdateProductsFromCart) => void;
  routeCart?: () => string;
  active?: boolean;
}

export const OutOfStock: Container<OutOfStockProps> = ({
  onCartProductsUpdate,
  routeCart,
  active = true,
}) => {
  const [items, setItems] = useState<ItemModel[]>([]);

  const removeOutOfStockItems = useCallback(() => {
    if (!onCartProductsUpdate) return;

    const update = items
      .filter((item) => item.outOfStock)
      .map((item) => ({ uid: item.uid, quantity: 0 }));

    onCartProductsUpdate(update);
  }, [items, onCartProductsUpdate]);

  useEffect(() => {
    if (!active) return;

    const onCartData = events.on(
      'cart/data',
      (data) => {
        const items = (data?.items || []) as ItemModel[];
        setItems(
          items.filter((item: ItemModel) => {
            return item.outOfStock || item.insufficientQuantity;
          })
        );
      },
      { eager: true }
    );

    return () => {
      onCartData?.off();
    };
  }, [active]);

  if (!active || items.length === 0) return null;

  const canRemoveOutOfStock = !items.some((item) => item.insufficientQuantity);

  return (
    <OutOfStockComponent
      items={items}
      routeCart={routeCart?.()}
      onRemoveOutOfStock={
        canRemoveOutOfStock ? removeOutOfStockItems : undefined
      }
    />
  );
};
